('old-data-berta2-all-20260501-01', '8a552b4a', U&'C''est une association intergerationnelle qui oeuvre depuis sa cr\00E9ation en faveur du savoir-faire r\00E9unionnais et de sa transmission aux g\00E9n\00E9rations futures pour la conservation de notre patrimoine que ce soit culinaire, artistiques, culturel et bien d''autres...\000A\000ACulinaire : Remettre au go\00FBt du jour les l\00E9gumes oubli\00E9es, valoriser les recettes d''antan, des grands-m\00E8res : p\00E2t\00E9 cr\00E9ole, g\00E2teau mariage, chemin fer, bonbon miel, colle pistaches, bonbon coco, initier aux nouvelles recettes : choca, vacoa, ti-jacques...\000ATransformation des produits locaux : fruits (gel\00E9es, confitures, sirops) \000Al\00E9gumes (achards, conserves enn bocaux, pickles)', 'Association Tradition et Passions', 'public', '0', 'Berta 2.0', U&'{"id":"8a552b4a","Nom commercial":"Association Tradition et Passions","Raison sociale":"","Motif Hors ligne":"","En ligne":"non","Zone":"sud","Nom de la commune":"Entre-Deux","Adresse":"24 rue Defaud, 97414 Entre-Deux - Ravine des Citrons","Site web":"","Groupe cat\00E9gorie":"D\00E9couverte","Nom cat\00E9gorie":"Patrimoine culturel","Nom sous cat\00E9gorie":"Restauration traditionnelle","Localisations":"Village","Code postal":"97414","Bureau postal":"Entre-Deux","Lieux-dits":"Ravine des Citrons","Prestations sur place":"mat\00E9riel pour l''activit\00E9 , grand espace , Propose des snacks , ateliers , Cuisine de produits frais locaux , repas originaux et traditionnels , Produits artisanaux","Prestations \00E0 proximit\00E9":"sentier de randonn\00E9e,commerce alimentaire,point de vue panoramique,site - lieu culturel","Mode de paiement":"Esp\00E8ces","Langues":"fran\00E7ais,cr\00E9ole","Fixe":"","Mobile":"0692 31 36 53","Autre t\00E9l\00E9phone":"","Fax":"","E-Mail":"dijoux.jacqueline@orange.fr","Capacit\00E9":"","Classement":"","Accroche":"Association Tradition et Passions","Descriptif":"C''est une association intergerationnelle qui oeuvre depuis sa cr\00E9ation en faveur du savoir-faire r\00E9unionnais et de sa transmission aux g\00E9n\00E9rations futures pour la conservation de notre patrimoine que ce soit culinaire, artistiques, culturel et bien d''autres...\\n\\nCulinaire : Remettre au go\00FBt du jour les l\00E9gumes oubli\00E9es, valoriser les recettes d''antan, des grands-m\00E8res : p\00E2t\00E9 cr\00E9ole, g\00E2teau mariage, chemin fer, bonbon miel, colle pistaches, bonbon coco, initier aux nouvelles recettes : choca, vacoa, ti-jacques...\\nTransformation des produits locaux : fruits (gel\00E9es, confitures, sirops) \\nl\00E9gumes (achards, conserves enn bocaux, pickles)","Descriptif du plan d''acc\00E8s":"","Jours et horaires d''ouverture":"","Labels":"","Date de cr\00E9ation - Etablissement":"5/5/2025","Date de fermeture":"","Fournisseur - Nom":"Mme Marie-Jacqueline DIJOUX","Fournisseur - SIRET":"92292010300012","Fournisseur - adresse":"Mme Marie-Jacqueline DIJOUX: 24 Rue Defaud, 97414 Entre-Deux","Fournisseur - contacts":"dijoux.jacqueline@orange.fr / 0692 31 36 53","Fournisseur - date de cr\00E9ation":"","Fournisseur - Code postal":"","Fournisseur - Bureau":"","Fournisseur - Code NAF":"","Fournisseur - Chambre consulaire":"","Fournisseur - Forme juridique":"","Fournisseur - CFE":"","Nb Produits":"","Coordonn\00E9es GPS":"-21.244707, 55.481211","Liste URL moteur":"","Tarif Montant":"","Tarif libell\00E9":"","Num taxe de s\00E9jour":"","Descriptif OTI":"","Accroche OTI":"","Status":"","commentaire":"","Date de derniere modification":"","Colones modifi\00E9es":"","Aire d''adh\00E9sion":"","source_system":"berta_v2_csv_export"}', 'pending', 'true');
